// lib/certificadoFundoPadrao.js
//
// Fundo padrao do certificado (frente e verso), embutido no codigo como
// data URI base64. Usado automaticamente quando um treinamento NAO tem
// sua propria imagem de fundo cadastrada (certificado_fundo_frente_base64
// / certificado_fundo_verso_base64 vazios), pra nao precisar reenviar essas
// duas imagens toda vez que um treinamento novo for criado.
//
// Se o treinamento tiver fundo proprio cadastrado, ele tem prioridade e
// este padrao nem entra em jogo (ver lib/certificado.js e
// api/player/certificado/index.js).

const FUNDO_FRENTE_PADRAO_BASE64 = 'data:image/jpeg;base64,';

const FUNDO_VERSO_PADRAO_BASE64 = 'data:image/jpeg;base64,';

module.exports = { FUNDO_FRENTE_PADRAO_BASE64, FUNDO_VERSO_PADRAO_BASE64 };
